import scala.xml._

class XmlConfigService {
  def loadXml(xmlString: String): Unit = {
    val xml = XML.loadString(xmlString)
    extractSettingsFromXml(xml)
  }
  
  private def extractSettingsFromXml(node: Node): Unit = node match {
    case e: Elem if e.label == "setting" =>
      val name = (e \ "@name").text
      val value = (e \ "@value").text
      println(s"Setting $name found with value $value")
      
    case _ => // do nothing for other nodes
  }
}